class Solution:
    def canCross(self, stones):
        positions = set(stones)
        last = stones[-1]
        import sys
        sys.setrecursionlimit(10000)
        from functools import lru_cache
        @lru_cache(None)
        def dfs(pos, k):
            if pos == last:
                return True
            for nk in (k - 1, k, k + 1):
                if nk > 0 and (pos + nk) in positions:
                    if dfs(pos + nk, nk):
                        return True
            return False
        if len(stones) >= 2 and stones[1] != 1:
            return False
        return dfs(stones[0], 0)

