class Solution:
    def canCross(self, stones):
        if stones[1] != 1:
            return False
        reach = {s: set() for s in stones}
        reach[stones[0]].add(0)
        last = stones[-1]
        for s in stones:
            for k in reach[s]:
                for nk in (k - 1, k, k + 1):
                    if nk > 0:
                        nxt = s + nk
                        if nxt == last:
                            return True
                        if nxt in reach:
                            reach[nxt].add(nk)
        return False

