var canCross = function(stones) {
    if (stones[1] !== 1) return false;
    const reach = new Map();
    for (const s of stones) reach.set(s, new Set());
    reach.get(stones[0]).add(0);
    const last = stones[stones.length - 1];
    for (const s of stones) {
        for (const k of reach.get(s)) {
            for (const nk of [k - 1, k, k + 1]) {
                if (nk > 0) {
                    const nxt = s + nk;
                    if (nxt === last) return true;
                    if (reach.has(nxt)) reach.get(nxt).add(nk);
                }
            }
        }
    }
    return false;
};
